const body = $json.body || $json;
const clean = (value, fallback = '') => String(value ?? fallback).trim();
const title = clean(body.title, 'Nova etapa Odessa');
const brief = clean(body.brief || body.description || body.message);
if (!brief) throw new Error('brief is required');
const priority = clean(body.priority, 'normal').toLowerCase();
const area = clean(body.area, 'produto').toLowerCase();
const targetChannel = clean(body.targetChannel, 'odessa-roadmap').replace(/^#/, '');
const constraints = Array.isArray(body.constraints) ? body.constraints.map((item) => String(item).trim()).filter(Boolean) : [];
return [{ json: { title, brief, priority, area, requestedBy: clean(body.requestedBy, 'Lucas'), constraints, targetChannel } }];

const response = $json;
const plan = response.projectPlan || {};
const channel = String(plan.slackRoute || 'odessa-roadmap').replace(/^#/, '');
const tasks = Array.isArray(plan.tasks) ? plan.tasks.slice(0, 6) : [];
const nextActions = Array.isArray(plan.nextActions) ? plan.nextActions.slice(0, 4) : [];
const taskText = tasks.length ? tasks.map((task) => `- ${task.id ? `*${task.id}* ` : ''}${task.title || task}`).join('\n') : '- Sem tarefas geradas';
const actionText = nextActions.length ? nextActions.map((action) => `- ${action}`).join('\n') : '- Revisar plano e escolher a primeira tarefa';
const text = `*${plan.title || 'Nova etapa Odessa'}*\n${plan.summary || ''}\n\n*Backlog inicial*\n${taskText}\n\n*Proximas acoes*\n${actionText}`;
const slackMessage = {
  channel: `#${channel}`,
  text,
  blocks: [
    { type: 'section', text: { type: 'mrkdwn', text: `*${plan.title || 'Nova etapa Odessa'}*\n${plan.summary || ''}` } },
    { type: 'section', text: { type: 'mrkdwn', text: `*Backlog inicial*\n${taskText}` } },
    { type: 'section', text: { type: 'mrkdwn', text: `*Proximas acoes*\n${actionText}` } }
  ]
};
return [{ json: { ok: response.ok !== false, projectPlan: plan, slackMessage } }];

const webhookUrl = String($env.N8N_SLACK_WEBHOOK_URL || $env.SLACK_WEBHOOK_URL || '').trim();
const slackDispatch = { configured: Boolean(webhookUrl), sent: false, status: null, error: null };
if (webhookUrl) {
  try {
    const response = await fetch(webhookUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ text: $json.slackMessage.text, blocks: $json.slackMessage.blocks })
    });
    slackDispatch.sent = response.ok;
    slackDispatch.status = response.status;
    if (!response.ok) slackDispatch.error = await response.text();
  } catch (error) {
    slackDispatch.error = error.message || 'Slack webhook failed';
  }
}
return [{ json: { ...$json, slackDispatch } }];

const plan = $json.projectPlan || {};
const createdAt = new Date().toISOString();
const safeTitle = String(plan.title || 'odessa-project').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '').slice(0, 54) || 'odessa-project';
const projectId = `ods-${safeTitle}-${createdAt.slice(0, 10)}`;
const artifact = {
  projectId,
  createdAt,
  brief: {
    title: plan.title,
    summary: plan.summary,
    slackRoute: plan.slackRoute
  },
  roadmap: {
    goals: plan.goals || [],
    milestones: plan.milestones || [],
    nextActions: plan.nextActions || []
  },
  tasks: plan.tasks || [],
  decisions: plan.decisions || [],
  risks: plan.risks || [],
  acceptanceCriteria: plan.acceptanceCriteria || [],
  slack: $json.slackMessage,
  slackDispatch: $json.slackDispatch || { configured: false, sent: false }
};
return [{ json: { ok: true, projectPlan: plan, slackMessage: $json.slackMessage, slackDispatch: $json.slackDispatch, artifact } }];
